import{_ as t,c as i,o as a,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Getting Started: Extend AI Agent Capabilities | Agent Skills","description":"Learn Agent Skills to extend AI coding agent capabilities. Discover three core features: React performance optimization, web design guidelines, and one-click deployment.","frontmatter":{"title":"Getting Started: Extend AI Agent Capabilities | Agent Skills","sidebarTitle":"Getting Started","subtitle":"Getting Started: Extend AI Agent Capabilities","description":"Learn Agent Skills to extend AI coding agent capabilities. Discover three core features: React performance optimization, web design guidelines, and one-click deployment.","tags":["Getting Started","AI Coding Agent","Claude","Skill Pack"],"order":10,"prerequisite":[]},"headers":[],"relativePath":"vercel-labs/agent-skills/start/getting-started/index.md","filePath":"vercel-labs/agent-skills/start/getting-started/index.md"}'),s={name:"vercel-labs/agent-skills/start/getting-started/index.md"};function n(r,e,o,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="getting-started-with-agent-skills" tabindex="-1">Getting Started with Agent Skills <a class="header-anchor" href="#getting-started-with-agent-skills" aria-label="Permalink to &quot;Getting Started with Agent Skills&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand what Agent Skills is and how it extends AI coding agent capabilities</li><li>Learn about the functionality and use cases of three core skill packs</li><li>Know when it&#39;s appropriate to use Agent Skills to improve development efficiency</li></ul><h2 id="your-current-challenges" tabindex="-1">Your Current Challenges <a class="header-anchor" href="#your-current-challenges" aria-label="Permalink to &quot;Your Current Challenges&quot;">​</a></h2><p>When using Claude, Cursor, or other AI coding agents in your daily work, you might encounter these problems:</p><ul><li>You want to follow best practices but aren&#39;t sure which rules to remember</li><li>You frequently repeat similar deployment operations and want automation</li><li>AI-generated code quality varies, lacking unified standards</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p><strong>Agent Skills is a skill pack system</strong>—providing extensible &quot;plugins&quot; for AI coding agents. Each skill contains:</p><ul><li><strong>SKILL.md</strong>: Skill definition file that tells the AI agent when to activate the skill</li><li><strong>scripts/</strong>: Helper scripts (such as deployment scripts) that execute specific tasks</li><li><strong>references/</strong>: Supporting documentation (optional) that provides detailed reference materials</li></ul><div class="tip custom-block"><p class="custom-block-title">Design Philosophy</p><p>Skills use an <strong>on-demand loading</strong> mechanism: only the skill name and description are loaded at startup, and the full content is read only when the AI determines it&#39;s needed. This reduces context usage and improves efficiency.</p></div><h2 id="available-skill-packs" tabindex="-1">Available Skill Packs <a class="header-anchor" href="#available-skill-packs" aria-label="Permalink to &quot;Available Skill Packs&quot;">​</a></h2><p>The project provides three skill packs, each targeting specific scenarios:</p><h3 id="react-best-practices" tabindex="-1">react-best-practices <a class="header-anchor" href="#react-best-practices" aria-label="Permalink to &quot;react-best-practices&quot;">​</a></h3><p>React and Next.js performance optimization guidelines from Vercel Engineering standards. Contains 50+ rules sorted by impact level.</p><p><strong>Use Cases</strong>:</p><ul><li>Writing new React components or Next.js pages</li><li>Reviewing code performance issues</li><li>Optimizing bundle size or loading time</li></ul><p><strong>Covered Categories</strong>:</p><ul><li>Eliminate Waterfalls (Critical)</li><li>Bundle Size Optimization (Critical)</li><li>Server Performance (High)</li><li>Client Side Data Fetching (Medium-High)</li><li>Re-render Optimization (Medium)</li><li>Rendering Performance (Medium)</li><li>JavaScript Micro-optimizations (Low-Medium)</li><li>Advanced Patterns (Low)</li></ul><h3 id="web-design-guidelines" tabindex="-1">web-design-guidelines <a class="header-anchor" href="#web-design-guidelines" aria-label="Permalink to &quot;web-design-guidelines&quot;">​</a></h3><p>Web interface design guidelines audit that checks code against nearly 100 best practices.</p><p><strong>Use Cases</strong>:</p><ul><li>Prompt: &quot;Review my UI&quot;</li><li>Check accessibility</li><li>Audit design consistency</li><li>Check performance and UX</li></ul><p><strong>Covered Categories</strong>:</p><ul><li>Accessibility (aria-labels, semantic HTML, keyboard handling)</li><li>Focus States (visible focus, focus-visible patterns)</li><li>Forms (autocompletion, validation, error handling)</li><li>Animations (prefers-reduced-motion, compositing-friendly transforms)</li><li>Images (sizing, lazy loading, alt text)</li><li>Typography, performance, navigation, and more</li></ul><h3 id="vercel-deploy-claimable" tabindex="-1">vercel-deploy-claimable <a class="header-anchor" href="#vercel-deploy-claimable" aria-label="Permalink to &quot;vercel-deploy-claimable&quot;">​</a></h3><p>One-click deployment of applications and websites to Vercel, returning preview links and ownership transfer links.</p><p><strong>Use Cases</strong>:</p><ul><li>Prompt: &quot;Deploy my app&quot;</li><li>Quickly share project previews</li><li>Configuration-free, zero-auth deployment</li></ul><p><strong>Core Features</strong>:</p><ul><li>Auto-detects 40+ frameworks (Next.js, Vite, Astro, etc.)</li><li>Returns preview URL (live site) and claim URL (transfer ownership)</li><li>Automatically handles static HTML projects</li><li>Excludes <code>node_modules</code> and <code>.git</code> during upload</li></ul><h2 id="how-skills-work" tabindex="-1">How Skills Work <a class="header-anchor" href="#how-skills-work" aria-label="Permalink to &quot;How Skills Work&quot;">​</a></h2><p>When using Claude or other AI agents, the skill activation flow is as follows:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[User enters task] --&gt; B[AI detects keywords&lt;br/&gt;e.g., Deploy, Review, Optimize]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Matches skill description]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Loads full SKILL.md content]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[Executes scripts or applies rules]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[Outputs results to user]</span></span></code></pre></div><p><strong>Example Flow</strong>:</p><ol><li><strong>User Input</strong>: &quot;Deploy my app&quot;</li><li><strong>AI Detection</strong>: Identifies keyword &quot;Deploy&quot;, matches <code>vercel-deploy</code> skill</li><li><strong>Load Skill</strong>: Reads full <code>SKILL.md</code> content</li><li><strong>Execute Deployment</strong>: <ul><li>Run <code>deploy.sh</code> script</li><li>Detect framework (read package.json)</li><li>Package project as tarball</li><li>Upload to Vercel API</li></ul></li><li><strong>Return Result</strong>:<div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;previewUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://skill-deploy-abc123.vercel.app&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claimUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://vercel.com/claim-deployment?code=...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li></ol><h2 id="when-to-use-this-approach" tabindex="-1">When to Use This Approach <a class="header-anchor" href="#when-to-use-this-approach" aria-label="Permalink to &quot;When to Use This Approach&quot;">​</a></h2><p>Best times to use Agent Skills:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Skill to Use</th><th>Example Trigger Prompt</th></tr></thead><tbody><tr><td>Writing React components</td><td>react-best-practices</td><td>&quot;Review this React component for performance issues&quot;</td></tr><tr><td>Optimizing Next.js pages</td><td>react-best-practices</td><td>&quot;Help me optimize this Next.js page&quot;</td></tr><tr><td>Checking UI quality</td><td>web-design-guidelines</td><td>&quot;Check accessibility of my site&quot;</td></tr><tr><td>Deploying projects</td><td>vercel-deploy-claimable</td><td>&quot;Deploy my app to production&quot;</td></tr></tbody></table><h2 id="security-model" tabindex="-1">Security Model <a class="header-anchor" href="#security-model" aria-label="Permalink to &quot;Security Model&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Security Note</p><ul><li><strong>Local Execution</strong>: All skills execute locally with no data uploaded to third-party services (except Vercel deployment API)</li><li><strong>On-Demand Activation</strong>: Skills only load detailed content when AI determines relevance, reducing privacy risk</li><li><strong>Open Source Transparent</strong>: All skills and scripts are open source and auditable</li></ul></div><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="skill-not-activated" tabindex="-1">Skill Not Activated <a class="header-anchor" href="#skill-not-activated" aria-label="Permalink to &quot;Skill Not Activated&quot;">​</a></h3><p>If a skill isn&#39;t activated, check:</p><ul><li>Whether the prompt contains enough keywords (such as &quot;Deploy&quot;, &quot;Review&quot;)</li><li>Whether the skill is correctly installed in the <code>~/.claude/skills/</code> directory</li><li>If using claude.ai, confirm the skill has been added to the project knowledge base</li></ul><h3 id="network-permissions" tabindex="-1">Network Permissions <a class="header-anchor" href="#network-permissions" aria-label="Permalink to &quot;Network Permissions&quot;">​</a></h3><p>Some skills require network access:</p><ul><li><code>vercel-deploy-claimable</code> needs access to Vercel deployment API</li><li><code>web-design-guidelines</code> needs to pull latest rules from GitHub</li></ul><p><strong>Solution</strong>: Add required domains in claude.ai/settings/capabilities.</p><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>Agent Skills is a skill pack system designed for AI coding agents, providing:</p><ul><li><strong>react-best-practices</strong>: 50+ React/Next.js performance optimization rules</li><li><strong>web-design-guidelines</strong>: Nearly 100 web design best practices</li><li><strong>vercel-deploy-claimable</strong>: One-click deployment to Vercel</li></ul><p>Skills use an on-demand loading mechanism to reduce context usage. Once installed, AI agents automatically activate corresponding skills for relevant tasks.</p><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../installation/">Installing Agent Skills</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Two installation methods: Claude Code and claude.ai</li><li>Configuring network permissions</li><li>Verifying that skills are correctly installed</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Skill pack list</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L7-L80" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>7-80</td></tr><tr><td>Skill structure explanation</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L103-L110" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>103-110</td></tr><tr><td>AGENTS.md specification</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>Full text</td></tr><tr><td>Skill directory structure</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L11-L20" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>11-20</td></tr><tr><td>SKILL.md format</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L29-L68" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>29-68</td></tr><tr><td>Skill packaging command</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L93-L96" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>93-96</td></tr><tr><td>User installation method</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L98-L110" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>98-110</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Build tool scripts</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/package.json" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/package.json</code></a></td><td>Full text</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li>No hardcoded constants</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>build.ts</code>: Builds AGENTS.md and test cases</li><li><code>validate.ts</code>: Validates rule file completeness</li><li><code>extract-tests.ts</code>: Extracts test cases from rules</li></ul></details>`,57)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
